import{_ as r,C as n,o as p,c as u,ag as l,E as a,w as o,a as t}from"./chunks/framework.BZohXCq9.js";const T=JSON.parse('{"title":"Pedido Rápido","description":"El acumulador de platos que envía el pedido completo por WhatsApp","frontmatter":{"title":"Pedido Rápido","description":"El acumulador de platos que envía el pedido completo por WhatsApp"},"headers":[],"relativePath":"food/pedido-rapido.md","filePath":"food/pedido-rapido.md"}'),c={name:"food/pedido-rapido.md"};function m(h,e,g,q,b,f){const i=n("Step"),s=n("Steps"),d=n("Warning");return p(),u("div",null,[e[5]||(e[5]=l('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>El Pedido Rápido es la función estrella de SYNTIfood. Permite que tus clientes toquen [+] en cada plato del menú, acumulen su pedido y lo envíen como un mensaje estructurado directamente a tu WhatsApp. <strong>No es un carrito de compras</strong> — es un acumulador simple tipo &quot;bloc de notas&quot;.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>En la landing (lo que ve tu cliente):</strong></p><ul><li>Cada plato del menú tiene un botón <strong>[+]</strong> al lado del precio</li><li>Al agregar ítems, aparece un botón flotante: <strong>&quot;Ver pedido (X items)&quot;</strong></li><li>Al tocar ese botón, se muestra el resumen y el botón <strong>&quot;Enviar pedido&quot;</strong></li></ul><p><strong>Configuración:</strong> Se activa automáticamente en el plan Anual de SYNTIfood. No requiere configuración adicional en el panel.</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><h3 id="flujo-del-pedido-rapido" tabindex="-1">Flujo del Pedido Rápido <a class="header-anchor" href="#flujo-del-pedido-rapido" aria-label="Permalink to &quot;Flujo del Pedido Rápido&quot;">​</a></h3>',8)),a(s,null,{default:o(()=>[a(i,{title:"El cliente navega tu menú"},{default:o(()=>[...e[0]||(e[0]=[t(" Ve las categorías con fotos y la lista de platos con precios. ",-1)])]),_:1}),a(i,{title:"Toca [+] en los platos que quiere"},{default:o(()=>[...e[1]||(e[1]=[t(" Cada toque agrega 1 unidad. Puede agregar múltiples platos de diferentes categorías. ",-1)])]),_:1}),a(i,{title:"Revisa el pedido"},{default:o(()=>[...e[2]||(e[2]=[t(' Toca **"Ver pedido (X items)"** → Ve el resumen: platos, cantidades, precios y total. ',-1)])]),_:1}),a(i,{title:"Envía por WhatsApp"},{default:o(()=>[...e[3]||(e[3]=[t(' Toca **"Enviar pedido"** → Se abre WhatsApp con el mensaje estructurado. ',-1)])]),_:1})]),_:1}),e[6]||(e[6]=l(`<h3 id="formato-del-mensaje-de-whatsapp" tabindex="-1">Formato del mensaje de WhatsApp <a class="header-anchor" href="#formato-del-mensaje-de-whatsapp" aria-label="Permalink to &quot;Formato del mensaje de WhatsApp&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🍽️ Pedido desde [Nombre del Negocio]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2× Arepa reina pepiada — REF 4.00 c/u</span></span>
<span class="line"><span>1× Tequeños (6 unidades) — REF 3.50</span></span>
<span class="line"><span>1× Jugo de guayaba — REF 2.50</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Total: REF 14.00</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Enviado desde syntiweb.com</span></span></code></pre></div><h3 id="que-pasa-despues" tabindex="-1">Qué pasa después <a class="header-anchor" href="#que-pasa-despues" aria-label="Permalink to &quot;Qué pasa después&quot;">​</a></h3><ol><li>El restaurante recibe el mensaje en WhatsApp</li><li>Confirma disponibilidad: <em>&quot;Todo disponible, listo en 20 min&quot;</em></li><li>Coordina el pago: <em>&quot;¿Pago Móvil o efectivo?&quot;</em></li><li>Prepara y entrega</li></ol><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li><strong>No es un carrito persistente</strong> — si el cliente cierra el navegador, se pierde el pedido</li><li><strong>No tiene checkout</strong> — no pide dirección, nombre ni datos del cliente</li><li><strong>No procesa pagos</strong> — el pago se coordina por WhatsApp</li><li><strong>No permite modificar cantidades</strong> fácilmente (solo agregar)</li><li><strong>No guarda historial de pedidos</strong> del cliente</li><li><strong>No tiene confirmación de recibido</strong> automática</li><li><strong>No calcula envío ni delivery</strong></li><li><strong>No tiene horario de pedidos</strong> — funciona 24/7 independientemente del horario</li></ul>`,6)),a(d,null,{default:o(()=>[...e[4]||(e[4]=[t(" El Pedido Rápido **no es un carrito de compras**. No tiene direcciones, formas de pago, ni confirmación automática. El restaurante debe confirmar disponibilidad y precio por WhatsApp. ",-1)])]),_:1}),e[7]||(e[7]=l('<h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Plan</th><th>Pedido Rápido</th></tr></thead><tbody><tr><td>Básico (REF 9/mes)</td><td>❌ No disponible</td></tr><tr><td>Semestral (REF 39)</td><td>❌ No disponible</td></tr><tr><td><strong>Anual (REF 69/año)</strong></td><td>✅ <strong>Incluido</strong></td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-pasteleria-dulce-tentacion-en-merida" tabindex="-1">Caso: Pastelería &quot;Dulce Tentación&quot; en Mérida <a class="header-anchor" href="#caso-pasteleria-dulce-tentacion-en-merida" aria-label="Permalink to &quot;Caso: Pastelería &quot;Dulce Tentación&quot; en Mérida&quot;">​</a></h3><p>Ana tiene una pastelería con plan Anual. Su menú tiene:</p><ul><li>Categoría &quot;Tortas&quot; (foto de torta de chocolate) <ul><li>Torta de chocolate REF 15</li><li>Torta tres leches REF 18</li><li>Cheesecake REF 12</li></ul></li><li>Categoría &quot;Postres individuales&quot; <ul><li>Brownie REF 3</li><li>Quesillo individual REF 4</li></ul></li></ul><p>Un cliente entra desde el QR pegado en la vitrina:</p><ol><li>Toca [+] en &quot;Torta de chocolate&quot; → pedido: 1 item</li><li>Toca [+] [+] en &quot;Brownie&quot; → pedido: 3 items (1 torta + 2 brownies)</li><li>Toca <strong>&quot;Ver pedido (3 items)&quot;</strong></li><li>Ve: Torta de chocolate REF 15 + 2× Brownie REF 6 = <strong>Total REF 21</strong></li><li>Toca <strong>&quot;Enviar pedido&quot;</strong> → Se abre WhatsApp</li></ol><p>Ana recibe: <em>&quot;1× Torta de chocolate — REF 15.00, 2× Brownie — REF 3.00 c/u, Total: REF 21.00&quot;</em></p><p>Ana responde: <em>&quot;¡Disponible! La torta la tengo lista. ¿La recoges o te la mando? Pago Móvil Banesco 04141234567&quot;</em></p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/food/que-es-syntifood.html">¿Qué es SYNTIfood?</a> — Planes y comparativa</li><li><a href="/shared/whatsapp.html">WhatsApp</a> — Cómo funciona el canal de comunicación</li><li><a href="/food/seccion-comandas.html">Comandas</a> — Visualización de pedidos recibidos</li></ul>',12))])}const E=r(c,[["render",m]]);export{T as __pageData,E as default};
